import sys

def main():
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    P = list(map(int, data[1:N+1]))

    ranks = [0] * N
    assigned = [False] * N
    r = 1

    while True:
        max_score = -1
        indices = []

        for i in range(N):
            if not assigned[i] and P[i] > max_score:
                max_score = P[i]
                indices = [i]
            elif not assigned[i] and P[i] == max_score:
                indices.append(i)

        if not indices:
            break

        for i in indices:
            ranks[i] = r

        r += len(indices)

    for rank in ranks:
        print(rank)

if __name__ == "__main__":
    main()
